public class LCS {
    public static int longestCommonSubsequence(String text1, String text2) {
        int m = text1.length(), n = text2.length();
        int[][] dp = new int[m+1][n+1]; // dp[0][*] = dp[*][0] = 0
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (text1.charAt(i-1) == text2.charAt(j-1)) {
                    dp[i][j] = dp[i-1][j-1] + 1;        // match: extend
                } else {
                    dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]); // skip one
                }
            }
        }
        return dp[m][n];
    }
    public static void main(String[] args) {
        System.out.println(longestCommonSubsequence("abcde", "ace"));      // 3
        System.out.println(longestCommonSubsequence("abc", "abc"));        // 3
        System.out.println(longestCommonSubsequence("abc", "def"));        // 0
        System.out.println(longestCommonSubsequence("RAZORPAY", "PAYTM")); // 3
        System.out.println("O(m×n) time and space — 2D DP table");
    }
}

