public class EditDistance {
    public static int minDistance(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[][] dp = new int[m+1][n+1];
        // Base cases: empty string transformations
        for (int i = 0; i <= m; i++) dp[i][0] = i; // delete i chars
        for (int j = 0; j <= n; j++) dp[0][j] = j; // insert j chars
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (word1.charAt(i-1) == word2.charAt(j-1)) {
                    dp[i][j] = dp[i-1][j-1];       // match: free
                } else {
                    dp[i][j] = 1 + Math.min(dp[i-1][j-1],  // replace
                                   Math.min(dp[i-1][j],    // delete from word1
                                            dp[i][j-1]));  // insert into word1
                }
            }
        }
        return dp[m][n];
    }
    public static void main(String[] args) {
        System.out.println(minDistance("horse", "ros"));          // 3
        System.out.println(minDistance("intention", "execution")); // 5
        System.out.println(minDistance("", "abc"));               // 3
        System.out.println(minDistance("abc", ""));               // 3
        System.out.println("O(m×n) time and space — Levenshtein DP");
    }
}

