public class LongestCommonSubstring {
    public static int longestCommonSubstring(String s1, String s2) {
        int m = s1.length(), n = s2.length(), maxLen = 0;
        int[][] dp = new int[m+1][n+1];
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (s1.charAt(i-1) == s2.charAt(j-1)) {
                    dp[i][j] = dp[i-1][j-1] + 1; // extend matching substring
                    maxLen = Math.max(maxLen, dp[i][j]);
                } else {
                    dp[i][j] = 0; // must be contiguous — reset on mismatch
                }
            }
        }
        return maxLen;
    }
    public static void main(String[] args) {
        System.out.println(longestCommonSubstring("abcde", "abfce"));    // 2
        System.out.println(longestCommonSubstring("RAZORPAY", "REPAY")); // 3
        System.out.println(longestCommonSubstring("abc", "xyz"));        // 0
        System.out.println("LCS Subsequence vs Substring:");
        System.out.println("  Subsequence: skip chars OK → max(dp[i-1][j], dp[i][j-1])");
        System.out.println("  Substring: must be contiguous → 0 on mismatch");
    }
}

