public class DistinctSubsequences {
    public static int numDistinct(String s, String t) {
        int m = s.length(), n = t.length();
        long[][] dp = new long[m+1][n+1]; // long: large numbers possible
        // Base: dp[i][0] = 1 — empty t is subsequence of any prefix of s (one way: pick nothing)
        for (int i = 0; i <= m; i++) dp[i][0] = 1;
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                dp[i][j] = dp[i-1][j]; // skip s[i]: don't use it
                if (s.charAt(i-1) == t.charAt(j-1))
                    dp[i][j] += dp[i-1][j-1]; // use s[i] to match t[j]
            }
        }
        return (int) dp[m][n];
    }
    public static void main(String[] args) {
        System.out.println(numDistinct("rabbbit", "rabbit")); // 3
        System.out.println(numDistinct("babgbag", "bag"));    // 5
        System.out.println("O(m×n) time and space");
        System.out.println("dp[i][j]: ways t[0..j-1] appears in s[0..i-1]");
    }
}

