public class ShortestCommonSupersequence {
    public static String shortestCommonSupersequence(String s1, String s2) {
        int m = s1.length(), n = s2.length();
        int[][] dp = new int[m+1][n+1];
        // LCS DP:
        for (int i = 1; i <= m; i++)
            for (int j = 1; j <= n; j++)
                dp[i][j] = s1.charAt(i-1)==s2.charAt(j-1)
                    ? dp[i-1][j-1]+1 : Math.max(dp[i-1][j], dp[i][j-1]);
        // Backtrack to build SCS:
        StringBuilder sb = new StringBuilder();
        int i = m, j = n;
        while (i > 0 && j > 0) {
            if (s1.charAt(i-1) == s2.charAt(j-1)) {
                sb.append(s1.charAt(i-1)); i--; j--; // in LCS: include once
            } else if (dp[i-1][j] > dp[i][j-1]) {
                sb.append(s1.charAt(i-1)); i--; // s1 char not in LCS
            } else {
                sb.append(s2.charAt(j-1)); j--; // s2 char not in LCS
            }
        }
        while (i > 0) { sb.append(s1.charAt(i-1)); i--; }
        while (j > 0) { sb.append(s2.charAt(j-1)); j--; }
        return sb.reverse().toString();
    }
    public static void main(String[] args) {
        System.out.println(shortestCommonSupersequence("abac", "cab")); // cabac
        System.out.println(shortestCommonSupersequence("abc", "abc"));  // abc
        System.out.println("SCS length = len1 + len2 - LCS");
    }
}

