public class WildcardMatching {
    public static boolean isMatch(String s, String p) {
        int m = s.length(), n = p.length();
        boolean[][] dp = new boolean[m+1][n+1];
        dp[0][0] = true; // empty matches empty
        // Pattern '*' can match empty: dp[0][j] = dp[0][j-1] if p[j-1]=='*'
        for (int j = 1; j <= n; j++)
            if (p.charAt(j-1) == '*') dp[0][j] = dp[0][j-1];
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                char pc = p.charAt(j-1);
                if (pc == '*') {
                    // '*' matches empty (dp[i][j-1]) or one more char (dp[i-1][j])
                    dp[i][j] = dp[i][j-1] || dp[i-1][j];
                } else if (pc == '?' || pc == s.charAt(i-1)) {
                    dp[i][j] = dp[i-1][j-1]; // single char match
                }
                // else: mismatch → dp[i][j] = false (default)
            }
        }
        return dp[m][n];
    }
    public static void main(String[] args) {
        System.out.println(isMatch("aa", "a"));       // false
        System.out.println(isMatch("aa", "*"));       // true
        System.out.println(isMatch("cb", "?a"));      // false
        System.out.println(isMatch("adceb", "*a*b")); // true
        System.out.println("O(m×n) DP — wildcard matching");
    }
}

