public class MinDeleteSum {
    public static int minimumDeleteSum(String s1, String s2) {
        int m = s1.length(), n = s2.length();
        int[][] dp = new int[m+1][n+1];
        // Base cases: delete all chars from one string
        for (int i = 1; i <= m; i++) dp[i][0] = dp[i-1][0] + s1.charAt(i-1);
        for (int j = 1; j <= n; j++) dp[0][j] = dp[0][j-1] + s2.charAt(j-1);
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (s1.charAt(i-1) == s2.charAt(j-1)) {
                    dp[i][j] = dp[i-1][j-1]; // match: no deletion needed
                } else {
                    dp[i][j] = Math.min(
                        dp[i-1][j] + s1.charAt(i-1), // delete s1[i]
                        dp[i][j-1] + s2.charAt(j-1)  // delete s2[j]
                    );
                }
            }
        }
        return dp[m][n];
    }
    public static void main(String[] args) {
        System.out.println(minimumDeleteSum("sea", "eat"));    // 231
        System.out.println(minimumDeleteSum("delete", "leet")); // 403
        System.out.println("O(m×n) — LCS variant with ASCII cost");
    }
}

