public class InterleavingStrings {
    public static boolean isInterleave(String s1, String s2, String s3) {
        int m = s1.length(), n = s2.length();
        if (m + n != s3.length()) return false;
        boolean[][] dp = new boolean[m+1][n+1];
        dp[0][0] = true;
        // Use only s1 chars for prefix:
        for (int i = 1; i <= m; i++)
            dp[i][0] = dp[i-1][0] && s1.charAt(i-1) == s3.charAt(i-1);
        // Use only s2 chars for prefix:
        for (int j = 1; j <= n; j++)
            dp[0][j] = dp[0][j-1] && s2.charAt(j-1) == s3.charAt(j-1);
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                dp[i][j] = (dp[i-1][j] && s1.charAt(i-1) == s3.charAt(i+j-1))
                         || (dp[i][j-1] && s2.charAt(j-1) == s3.charAt(i+j-1));
            }
        }
        return dp[m][n];
    }
    public static void main(String[] args) {
        System.out.println(isInterleave("aabcc","dbbca","aadbbcbcac")); // true
        System.out.println(isInterleave("aabcc","dbbca","aadbbbaccc")); // false
        System.out.println(isInterleave("","",""));                      // true
        System.out.println("O(m×n) DP — interleaving check");
    }
}

