public class EditDistanceOptimized {
    // O(m×n) space — standard
    static int editDistanceFull(String s1, String s2) {
        int m=s1.length(), n=s2.length();
        int[][] dp=new int[m+1][n+1];
        for(int i=0;i<=m;i++) dp[i][0]=i;
        for(int j=0;j<=n;j++) dp[0][j]=j;
        for(int i=1;i<=m;i++)
            for(int j=1;j<=n;j++)
                dp[i][j]=s1.charAt(i-1)==s2.charAt(j-1)?dp[i-1][j-1]:1+Math.min(dp[i-1][j-1],Math.min(dp[i-1][j],dp[i][j-1]));
        return dp[m][n];
    }
    // O(n) space — rolling array
    static int editDistanceRolling(String s1, String s2) {
        int m=s1.length(), n=s2.length();
        int[] prev=new int[n+1], curr=new int[n+1];
        for(int j=0;j<=n;j++) prev[j]=j; // base: empty s1
        for(int i=1;i<=m;i++){
            curr[0]=i; // base: empty s2 prefix
            for(int j=1;j<=n;j++){
                if(s1.charAt(i-1)==s2.charAt(j-1)) curr[j]=prev[j-1];
                else curr[j]=1+Math.min(prev[j-1],Math.min(prev[j],curr[j-1]));
            }
            int[] tmp=prev; prev=curr; curr=tmp;
        }
        return prev[n];
    }
    public static void main(String[] args){
        String s1="horse", s2="ros";
        int full=editDistanceFull(s1,s2), rolling=editDistanceRolling(s1,s2);
        System.out.println("Full O(mn):    "+full);
        System.out.println("Rolling O(n):  "+rolling);
        System.out.println("Same result:   "+(full==rolling));
        System.out.printf("Full space:    %d ints = %d bytes%n",(s1.length()+1)*(s2.length()+1),(s1.length()+1)*(s2.length()+1)*4);
        System.out.printf("Rolling space: %d ints = %d bytes%n",2*(s2.length()+1),2*(s2.length()+1)*4);
    }
}

