        return lcs(s,rev);
    }
    public static void main(String[] args){
        System.out.println("=== String DP Synthesis ===");
        System.out.println("1. LCS('abcde','ace')="+lcs("abcde","ace"));
        System.out.println("2. editDistance('horse','ros')="+editDistance("horse","ros"));
        System.out.println("3. longestPalinSubseq('bbbab')="+longestPalindromeSubseq("bbbab"));
